     5|//  Manual owner sign-in against the SAME production Supabase Auth project
     6|//  the Android app uses (expo/lib/supabase.ts). The owner types their email
     7|//  and password by hand — there is no automatic, silent, or end-to-end sign-in
     8|//  anywhere in this flow. On success the service returns a real Supabase
     9|//  session (access_token, refresh_token, expires_at) the app keeps in memory.
    10|//
    11|
    12|import Foundation
    13|
    14|enum OwnerAuthError: LocalizedError {
    15|    case badURL
    16|    case notConfigured
    17|    case httpError(Int, String)
    18|    case invalidCredentials
    19|    case emailNotConfirmed
    20|    case rateLimited
    21|    case networkFailure(String)
    22|
    23|    var errorDescription: String? {
    24|        switch self {
    25|        case .badURL: return "Invalid Supabase Auth endpoint URL."
    26|        case .notConfigured: return "Supabase is not configured. Rebuild the app with valid credentials."
    27|        case .httpError(let code, let message): return message.isEmpty ? "Sign-in failed (HTTP \(code))." : message
    28|        case .invalidCredentials: return "Invalid email or password. Please check your credentials and try again."
    29|        case .emailNotConfirmed: return "Your email is not confirmed yet. Confirm your email before signing in."
    30|        case .rateLimited: return "Too many sign-in attempts. Please wait a minute and try again."
    31|        case .networkFailure(let message): return message
    32|        }
    33|    }
    34|}
    35|
    36|struct OwnerSession: Codable, Equatable {
    37|    let accessToken: String
    38|    let refreshToken: String
    39|    let expiresAt: Int
    40|    let expiresAtIso: String
    41|    let userId: String
    42|    let email: String
    43|
    44|    enum CodingKeys: String, CodingKey {
    45|        case accessToken = "access_token"
    46|        case refreshToken = "refresh_token"
    47|        case expiresAt = "expires_at"
    48|        case userId = "user_id"
    49|        case email
    50|        case expiresAtIso = "expires_at_iso"
    51|    }
    52|
    53|    var isExpired: Bool {
    54|        guard expiresAt > 0 else { return true }
    55|        return Date(timeIntervalSince1970: TimeInterval(expiresAt)).addingTimeInterval(-60) <= Date()
    56|    }
