    59|struct OwnerAuthService {
    60|    /// Production Supabase project — identical to EXPO_PUBLIC_SUPABASE_URL in the Android app.
    61|    private static let fallbackBaseURL = "https://kvclcdjmjghndxsngfzb.supabase.co"
    62|    /// Public anon key — the same client-side key already shipped in the Android bundle.
    63|    private static let fallbackAnonKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Imt2Y2xjZGptamdobmR4c25nZnpiIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzMxOTQwMjcsImV4cCI6MjA4ODc3MDAyN30.OLDwa21VHQNs151AD-8k--_HigQ2d-N7yJfFn5UeNPk"
    64|
    65|    static var baseURL: String {
    66|        let configured = Config.EXPO_PUBLIC_SUPABASE_URL
    67|        if configured.hasPrefix("https://"), configured.contains(".supabase.co") {
    68|            return configured
    69|        }
    70|        return fallbackBaseURL
    71|    }
    72|
    73|    static var anonKey: String {
    74|        let configured = Config.EXPO_PUBLIC_SUPABASE_ANON_KEY
    75|        if configured.hasPrefix("eyJ"), configured.count > 100 {
    76|            return configured
    77|        }
    78|        return fallbackAnonKey
    79|    }
    80|
    81|    static var isConfigured: Bool {
    82|        return !baseURL.isEmpty && !anonKey.isEmpty
    83|    }
    84|
    85|    /// Manual owner sign-in: the owner types their email and password.
    86|    /// Performs a Supabase Auth password grant and returns a real session.
    87|    static func signIn(email: String, password: String) async throws -> OwnerSession {
    88|        guard isConfigured else {
    89|            throw OwnerAuthError.notConfigured
    90|        }
    91|        let trimmedEmail = email.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    92|        let trimmedPassword = password
    93|        guard !trimmedEmail.isEmpty, !trimmedPassword.isEmpty else {
    94|            throw OwnerAuthError.invalidCredentials
    95|        }
    96|
    97|        guard let url = URL(string: "\(baseURL)/auth/v1/token?grant_type=password") else {
    98|            throw OwnerAuthError.badURL
    99|        }
   100|
   101|        var request = URLRequest(url: url)
   102|        request.httpMethod = "POST"
   103|        request.timeoutInterval = 25
   104|        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
   105|        request.setValue(anonKey, forHTTPHeaderField: "apikey")
   106|        request.setValue("Bearer \(anonKey)", forHTTPHeaderField: "Authorization")
   107|
   108|        let body: [String: String] = ["email": trimmedEmail, "password": trimmedPassword]
   109|        request.httpBody = try JSONSerialization.data(withJSONObject: body)
   110|
   111|        let (data, response): (Data, URLResponse)
   112|        do {
   113|            (data, response) = try await URLSession.shared.data(for: request)
   114|        } catch {
   115|            throw OwnerAuthError.networkFailure(error.localizedDescription)
   116|        }
   117|
   118|        guard let http = response as? HTTPURLResponse else {
   119|            throw OwnerAuthError.networkFailure("No HTTP response from Supabase Auth.")
   120|        }
   121|
   122|        let raw = String(data: data, encoding: .utf8) ?? ""
   123|        guard let parsed = try? JSONDecoder().decode(SupabaseTokenResponse.self, from: data) else {
   124|            if http.statusCode == 400 || http.statusCode == 401 {
   125|                throw OwnerAuthError.invalidCredentials
   126|            }
   127|            if http.statusCode == 429 {
   128|                throw OwnerAuthError.rateLimited
   129|            }
   130|            throw OwnerAuthError.httpError(http.statusCode, raw)
   131|        }
   132|
   133|        if http.statusCode == 400 || http.statusCode == 401 {
   134|            let lower = (parsed.errorDescription ?? parsed.error ?? parsed.msg ?? "").lowercased()
   135|            if lower.contains("email") && lower.contains("confirm") {
   136|                throw OwnerAuthError.emailNotConfirmed
   137|            }
   138|            throw OwnerAuthError.invalidCredentials
   139|        }
   140|        if http.statusCode == 429 {
   141|            throw OwnerAuthError.rateLimited
   142|        }
   143|        guard (200...299).contains(http.statusCode),
   144|              let accessToken = parsed.accessToken,
   145|              let refreshToken = parsed.refreshToken,
   146|              let userId = parsed.user?.id,
   147|              let emailValue = parsed.user?.email else {
   148|            throw OwnerAuthError.httpError(http.statusCode, parsed.errorDescription ?? parsed.error ?? "")
   149|        }
   150|
   151|        let expiresAt = parsed.expiresAt ?? 0
   152|        return OwnerSession(
   153|            accessToken: accessToken,
   154|            refreshToken: refreshToken,
   155|            expiresAt: expiresAt,
   156|            expiresAtIso: expiresAt > 0
   157|                ? ISO8601DateFormatter().string(from: Date(timeIntervalSince1970: TimeInterval(expiresAt)))
   158|                : ISO8601DateFormatter().string(from: Date()),
   159|            userId: userId,
   160|            email: emailValue
   161|        )
   162|    }
   163|}
   164|
   165|private struct SupabaseTokenResponse: Decodable {
   166|    let accessToken: String?
   167|    let refreshToken: String?
   168|    let expiresAt: Int?
   169|    let user: SupabaseUser?
   170|    let error: String?
   171|    let errorDescription: String?
   172|    let msg: String?
   173|
   174|    enum CodingKeys: String, CodingKey {
   175|        case accessToken = "access_token"
   176|        case refreshToken = "refresh_token"
   177|        case expiresAt = "expires_at"
   178|        case user
   179|        case error
   180|        case errorDescription = "error_description"
   181|        case msg
   182|    }
   183|}
   184|
   185|private struct SupabaseUser: Decodable {
   186|    let id: String?
   187|    let email: String?
   188|}

