   432|async function withTimeout<T>(operation: () => Promise<T>, timeoutMs: number, label: string, fallbackValue: T): Promise<T> {
   433|  return await new Promise<T>((resolve, reject) => {
   434|    let settled = false;
   435|
   436|    const timeout = setTimeout(() => {
   437|      if (settled) {
   438|        return;
   439|      }
   440|
   441|      settled = true;
   442|      console.log('[Auth] Operation timed out:', label, timeoutMs, 'ms');
   443|      resolve(fallbackValue);
   444|    }, timeoutMs);
   445|
   446|    void operation()
   447|      .then((result) => {
   448|        if (settled) {
   449|          return;
   450|        }
   451|
   452|        settled = true;
   453|        clearTimeout(timeout);
   454|        resolve(result);
   455|      })
   456|      .catch((error) => {
   457|        if (settled) {
   458|          return;
   459|        }
   460|
   461|        settled = true;
   462|        clearTimeout(timeout);
   463|        reject(error);
   464|      });
   465|  });
